Here's a basic example of how you can do this:

```csharp
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.Net.Http;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet]
    [Route("{proxyUrl}")]
    public async Task<IActionResult> ProxyRequest(string proxyUrl)
    {
        try
        {
            var request = new HttpRequestMessage(HttpMethod.Get, proxyUrl);
            var response = await _httpClient.SendAsync(request);

            response.EnsureSuccessStatusCode();

            return new OkObjectResult(await response.Content.ReadAsStringAsync());
        }
        catch (HttpRequestException ex)
        {
            return StatusCode(500, ex.Message);
        }
    }
}
```

